phase1.code:
#include <iostream>
#include <array>
#include <string>

int main() {
    std::cout << "=== std::array — Fixed-Size Collections ===" << std::endl;

    // 1. Creating arrays
    std::cout << "\n--- Creating arrays ---" << std::endl;
    std::array<int, 5> scores = {10, 20, 30, 40, 50};
    std::array<std::string, 3> names = {"Hero", "Aragorn", "Gandalf"};

    // 2. Accessing elements
    std::cout << "\n--- Accessing elements ---" << std::endl;
    std::cout << "scores[0]: " << scores[0] << std::endl;
    std::cout << "scores.at(1): " << scores.at(1) << std::endl;
    std::cout << "scores.front(): " << scores.front() << std::endl;
    std::cout << "scores.back(): " << scores.back() << std::endl;

    // 3. Size and iteration
    std::cout << "\n--- Iteration ---" << std::endl;
    std::cout << "Size: " << scores.size() << std::endl;

    for (int s : scores) {
        std::cout << s << " ";
    }
    std::cout << std::endl;

    // 4. C-style array compatibility
    std::cout << "\n--- C-style array compatibility ---" << std::endl;
    int* dataPtr = scores.data();  // Get raw pointer
    std::cout << "First element via pointer: " << *dataPtr << std::endl;

    // 5. Filling and modifying
    std::cout << "\n--- Filling and modifying ---" << std::endl;
    std::array<int, 5> health;
    health.fill(100);  // Fill all with 100

    for (int h : health) {
        std::cout << h << " ";
    }
    std::cout << std::endl;

    health[2] = 50;  // Individual modification
    health.at(4) = 75;
    std::cout << "After modifications: ";
    for (int h : health) {
        std::cout << h << " ";
    }
    std::cout << std::endl;

    // 6. Comparing arrays
    std::cout << "\n--- Comparing arrays ---" << std::endl;
    std::array<int, 3> a = {1, 2, 3};
    std::array<int, 3> b = {1, 2, 3};
    std::array<int, 3> c = {4, 5, 6};

    std::cout << "a == b: " << (a == b) << std::endl;
    std::cout << "a == c: " << (a == c) << std::endl;

    // 7. Game use: player stats
    std::cout << "\n--- Player Stats (array) ---" << std::endl;
    std::array<int, 4> playerStats = {100, 20, 15, 30};  // HP, ATK, DEF, SPD
    std::array<std::string, 4> statNames = {"HP", "ATK", "DEF", "SPD"};

    for (size_t i = 0; i < playerStats.size(); i++) {
        std::cout << statNames[i] << ": " << playerStats[i] << std::endl;
    }

    std::cout << "\n--- std::array vs C-style array ---" << std::endl;
    std::cout << "std::array advantages:" << std::endl;
    std::cout << "  ✅ Knows its own size" << std::endl;
    std::cout << "  ✅ Bounds checking with at()" << std::endl;
    std::cout << "  ✅ Works with STL algorithms" << std::endl;
    std::cout << "  ✅ Can be copied and compared" << std::endl;

    return 0;
}

phase2.brokenCode:
#include <iostream>
#include <array>

int main() {
    std::array<int, 3> arr = {1, 2, 3};

    // Accessing out of bounds!
    std::cout << arr[3] << std::endl;  // No bounds check!

    // This would throw an exception!
    // std::cout << arr.at(3) << std::endl;

    return 0;
}

phase2.explanation:
`std::array::operator[]` does NOT check bounds! Just like C-style arrays.

**What's happening:**
1. `arr` has 3 elements (indices 0-2)
2. `arr[3]` accesses out of bounds
3. Undefined behavior — might print garbage, might crash

**The fix:**
```cpp
// Use .at() for bounds checking (throws exception)
try {
    std::cout << arr.at(3) << std::endl;
} catch (const std::out_of_range& e) {
    std::cout << "Out of bounds!" << std::endl;
}
```

**PlusPlus-chan says:**
"`operator[]` is fast but dangerous. `at()` is safe but slower. Choose based on your needs."

