#include <iostream>
#include <array>

int main() {
    std::array<int, 5> playerLevels = {1, 2, 3, 4, 5};

    std::cout << "Player levels: ";
    for (int level : playerLevels) {
        std::cout << level << " ";
    }
    std::cout << std::endl;

    playerLevels[2] = 10;
    playerLevels.back() = 15;

    std::cout << "After modifications: ";
    for (int level : playerLevels) {
        std::cout << level << " ";
    }
    std::cout << std::endl;

    std::cout << "Size: " << playerLevels.size() << std::endl;

    std::array<int, 5> health;
    health.fill(100);

    std::cout << "Health: ";
    for (int h : health) {
        std::cout << h << " ";
    }
    std::cout << std::endl;

    return 0;
}
